import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

function ViewApplications() {
  const [apps, setApps] = useState([]);
  const navigate = useNavigate();

  /* =========================
     LOAD LOGGED USER
  ========================= */
  const loggedUser =
    JSON.parse(localStorage.getItem("loggedInUser")) || null;

  /* =========================
     LOAD APPLICATIONS
  ========================= */
  const loadApplications = () => {
    const stored =
      JSON.parse(localStorage.getItem("applications")) || [];
    setApps(stored);
  };

  useEffect(() => {
    loadApplications();
  }, []);

  /* =========================
     UPDATE STATUS (ADMIN)
  ========================= */
  const updateStatus = (id, status) => {
    const updated = apps.map(app =>
      app.id === id ? { ...app, status } : app
    );

    setApps(updated);
    localStorage.setItem("applications", JSON.stringify(updated));
  };

  /* =========================
     EMPLOYEE NAME RESOLUTION
  ========================= */
  const getEmployeeName = (a) => {
    if (a.employeeName) return a.employeeName;
    if (a.employee) return a.employee;

    const employees =
      JSON.parse(localStorage.getItem("employees")) || [];

    const emp = employees.find(
      e =>
        String(e.empId) === String(a.empId) ||
        String(e.email) === String(a.email)
    );

    if (!emp) return "Unknown";

    return `${emp.firstName || ""} ${emp.lastName || ""}`.trim();
  };

  /* =========================
     ROLE GUARD
  ========================= */
  if (loggedUser?.role !== "admin") {
    return <p style={{ marginTop: "25px" }}>Access Denied</p>;
  }

  return (
    <div style={{ marginTop: "25px" }}>
      <h2>Job Applications (Admin)</h2>

      <table className="designation-table">
        <thead>
          <tr>
            <th>S.No</th>
            <th>Employee</th>
            <th>Email</th>
            <th>Job Title</th>
            <th>Status</th>
            <th>Applied Date</th>
            <th>Action</th>
          </tr>
        </thead>

        <tbody>
          {apps.length === 0 ? (
            <tr>
              <td colSpan="7" style={{ textAlign: "center" }}>
                No Applications Found
              </td>
            </tr>
          ) : (
            apps.map((a, i) => (
              <tr key={a.id}>
                <td>{i + 1}</td>
                <td>{getEmployeeName(a)}</td>
                <td>{a.email}</td>
                <td>{a.jobTitle}</td>
                <td>{a.status}</td>
                <td>{a.appliedDate || "--"}</td>

                <td style={{ display: "flex", gap: "10px" }}>
                  {/* ===== PENDING ===== */}
                  {a.status === "Pending" && (
                    <>
                      <button
                        onClick={() =>
                          updateStatus(a.id, "Approved")
                        }
                      >
                        Approve
                      </button>

                      <button
                        onClick={() =>
                          updateStatus(a.id, "Rejected")
                        }
                      >
                        Reject
                      </button>
                    </>
                  )}

                  {/* ===== APPROVED ===== */}
                  {a.status === "Approved" && (
                    <button
                      onClick={() =>
                        navigate(
                          `/dashboard/recruitment/offer-letter/${a.id}`
                        )
                      }
                    >
                      Create Offer
                    </button>
                  )}

                  {/* ===== OFFER SENT ===== */}
                  {a.status === "OFFER_SENT" && (
                    <>
                      <button
                        onClick={() =>
                          navigate(
                            `/dashboard/recruitment/offer-letter/${a.id}`
                          )
                        }
                      >
                        Edit Offer
                      </button>

                      <button
                        onClick={() =>
                          navigate(
                            `/dashboard/recruitment/offer-preview/${a.id}`
                          )
                        }
                      >
                        View Offer
                      </button>
                    </>
                  )}
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
}

export default ViewApplications;
